package com.stock.portfolio.controller;
import com.stock.common.dto.ApiResponse; import com.stock.portfolio.dto.*; import com.stock.portfolio.service.PortfolioService; import jakarta.validation.Valid; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/portfolios") public class PortfolioController { private final PortfolioService service; public PortfolioController(PortfolioService s){service=s;} @PostMapping("/buy") public ApiResponse<PortfolioResponse> buy(@Valid @RequestBody TradeRequest r){return ApiResponse.created(service.buy(r));} @PostMapping("/sell") public ApiResponse<PortfolioResponse> sell(@Valid @RequestBody TradeRequest r){return ApiResponse.success(service.sell(r),"Sell order executed");} @GetMapping("/{userId}") public ApiResponse<List<PortfolioResponse>> holdings(@PathVariable UUID userId){return ApiResponse.success(service.holdings(userId),"Portfolio retrieved");} @GetMapping("/{userId}/{symbol}") public ApiResponse<PortfolioResponse> holding(@PathVariable UUID userId,@PathVariable String symbol){return ApiResponse.success(service.holding(userId,symbol),"Holding retrieved");} @GetMapping("/{userId}/{symbol}/transactions") public ApiResponse<List<TransactionResponse>> history(@PathVariable UUID userId,@PathVariable String symbol){return ApiResponse.success(service.history(userId,symbol),"Transactions retrieved");} }
